#include <stdio.h>
#include <string.h>
#define MAX 100
int dp[MAX][MAX];
char necklaces[MAX][MAX];
int main() {
    int T, K, N, i, j, k, len;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &K);
        for (i = 0; i < K; i++) {
            scanf("%s", necklaces[i]);
        }
        // Initialize dp array
        for (i = 0; i <= K; i++) {
            for (j = 0; j <= N; j++) {
                dp[i][j] = 0;
            }
        }
        // Fill up dp array
        for (i = 1; i <= K; i++) {
            for (j = 1; j <= N; j++) {
                if (necklaces[i-1][j-1] == 'B') {
                    dp[i][j] = dp[i-1][j-1] + 1;
                } else {
                    dp[i][j] = dp[i-1][j-1] + 1;
                }
            }
        }
        // Construct shortest supersequence
        len = 0;
        for (i = K; i > 0; i--) {
            for (j = N; j > 0; j--) {
                if (dp[i][j] != dp[i-1][j-1]) {
                    printf("%c", necklaces[i-1][j-1]);
                    len++;
                }
            }
        }
        printf("\n");
    }
    return 0;
}

