import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int K = sc.nextInt();
            String[] necklaces = new String[K];
            for (int i = 0; i < K; i++) {
                necklaces[i] = sc.next();
            }
            // Initialize dp array
            int[][] dp = new int[K + 1][8 + 1];
            for (int i = 0; i <= K; i++) {
                for (int j = 0; j <= 8; j++) {
                    dp[i][j] = 0;
                }
            }
            // Fill up dp array
            for (int i = 1; i <= K; i++) {
                for (int j = 1; j <= 8; j++) {
                    if (necklaces[i - 1].charAt(j - 1) == 'B') {
                        dp[i][j] = dp[i - 1][j - 1] + 1;
                    } else {
                        dp[i][j] = dp[i - 1][j - 1] + 1;
                    }
                }
            }
            // Construct shortest supersequence
            int len = 0;
            for (int i = K; i > 0; i--) {
                for (int j = 8; j > 0; j--) {
                    if (dp[i][j] != dp[i - 1][j - 1]) {
                        System.out.print(necklaces[i - 1].charAt(j - 1));
                        len++;
                    }
                }
            }
            System.out.println();
        }
    }
}

